#include <stdio.h>
#include <string.h>
#include <ctype.h>

void trim(char *s) {
    int start = 0;
    while (s[start] && isspace((unsigned char)s[start])) start++;
    int end = strlen(s) - 1;
    while (end >= start && isspace((unsigned char)s[end])) end--;
    int j = 0;
    for (int i = start; i <= end; ++i) s[j++] = s[i];
    s[j] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[256];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        trim(line);
        int len = strlen(line);
        // reverse in place
        for (int i = 0; i < len / 2; ++i) {
            char tmp = line[i];
            line[i] = line[len - 1 - i];
            line[len - 1 - i] = tmp;
        }
        printf("Reversed characters in your name: [");
        for (int i = 0; i < len; ++i) {
            printf("'%c'", line[i]);
            if (i != len - 1) printf(", ");
        }
        printf("]\n");
    }
    return 0;
}

